public record SearchCriteria(string Query, int Page, int PageSize, string SortBy);

public class ProductSearchService {
  public string Search(SearchCriteria criteria) {
    return $"{criteria.Query}:{criteria.Page}:{criteria.PageSize}:{criteria.SortBy}";
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Search_UsesAllCriteriaFields() {
  var service = new ProductSearchService();
  var criteria = new SearchCriteria("phone", 2, 25, "price");
  Assert.AreEqual("phone:2:25:price", service.Search(criteria));
}

[TestMethod]
public void ParameterObject_ImprovesCallClarity() {
  var criteria = new SearchCriteria("book", 1, 10, "name");
  Assert.AreEqual("book", criteria.Query);
}
